import{_ as t,o as a,c as n,a2 as i}from"./chunks/framework.ufzXw1qY.js";const g=JSON.parse('{"title":"How to Configure New Agents","description":"","frontmatter":{},"headers":[],"relativePath":"guide/how-to-configure-agents.md","filePath":"guide/how-to-configure-agents.md"}'),o={name:"guide/how-to-configure-agents.md"};function r(l,e,s,c,d,p){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="how-to-configure-new-agents" tabindex="-1">How to Configure New Agents <a class="header-anchor" href="#how-to-configure-new-agents" aria-label="Permalink to &quot;How to Configure New Agents&quot;">​</a></h1><p>This page describes the current OpenSIN path for introducing new agents without creating duplicate repos or drifting away from canonical ownership.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Before creating any new agent surface, read <a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/CANONICAL-REPOS.md" target="_blank" rel="noreferrer"><code>OpenSIN-overview/docs/CANONICAL-REPOS.md</code></a>. Many new agent ideas belong inside an existing <code>Team-SIN-*</code> monorepo instead of a brand-new repository.</p></div><h2 id="step-1-decide-where-the-agent-belongs" tabindex="-1">Step 1: Decide Where the Agent Belongs <a class="header-anchor" href="#step-1-decide-where-the-agent-belongs" aria-label="Permalink to &quot;Step 1: Decide Where the Agent Belongs&quot;">​</a></h2><p>Use this rule first:</p><ul><li>if the agent belongs to an existing team, add it to that <code>Team-SIN-*</code> repo</li><li>if it requires a new standalone agent repo, start from <code>Template-SIN-Agent</code></li><li>if you are unsure, open a repo proposal in <code>OpenSIN-overview</code> before coding</li></ul><h2 id="step-2-use-the-canonical-template" tabindex="-1">Step 2: Use the Canonical Template <a class="header-anchor" href="#step-2-use-the-canonical-template" aria-label="Permalink to &quot;Step 2: Use the Canonical Template&quot;">​</a></h2><p>OpenSIN standardizes new standalone agents from:</p><ul><li><a href="https://github.com/OpenSIN-AI/Template-SIN-Agent" target="_blank" rel="noreferrer"><code>Template-SIN-Agent</code></a></li></ul><p>This template is the canonical blueprint for new A2A-capable agents.</p><h2 id="step-3-register-the-agent-in-canonical-config" tabindex="-1">Step 3: Register the Agent in Canonical Config <a class="header-anchor" href="#step-3-register-the-agent-in-canonical-config" aria-label="Permalink to &quot;Step 3: Register the Agent in Canonical Config&quot;">​</a></h2><p>Agent registration and model routing belong in the canonical OpenCode stack:</p><ul><li><code>OpenSIN-AI/Infra-SIN-OpenCode-Stack</code></li><li>local <code>~/.config/opencode/*</code> files when working on a machine-specific setup</li></ul><p>Update only the canonical config locations. Do not invent parallel config repos.</p><h2 id="step-4-define-the-agent-contract" tabindex="-1">Step 4: Define the Agent Contract <a class="header-anchor" href="#step-4-define-the-agent-contract" aria-label="Permalink to &quot;Step 4: Define the Agent Contract&quot;">​</a></h2><p>Every production-grade agent needs at minimum:</p><ul><li><code>agent.json</code></li><li><code>.well-known/agent-card.json</code></li><li><code>AGENTS.md</code></li><li>governance metadata required by the template</li></ul><h2 id="step-5-verify-ownership-and-exposure" tabindex="-1">Step 5: Verify Ownership and Exposure <a class="header-anchor" href="#step-5-verify-ownership-and-exposure" aria-label="Permalink to &quot;Step 5: Verify Ownership and Exposure&quot;">​</a></h2><p>Before claiming the agent is ready:</p><ul><li>confirm the owning repo is canonical</li><li>confirm the docs point to the right repo and surface</li><li>confirm any public endpoint is verified before publishing it in docs</li></ul><h2 id="step-6-publish-safely" tabindex="-1">Step 6: Publish Safely <a class="header-anchor" href="#step-6-publish-safely" aria-label="Permalink to &quot;Step 6: Publish Safely&quot;">​</a></h2><p>Public docs must not expose internal IPs, internal dashboards, or unverified production endpoints. If an endpoint is not publicly verified, document it as internal/unverified instead of presenting it as final truth.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/guide/agent-configuration.html">Agent Configuration</a></li><li><a href="/tutorials/custom-agents.html">Building Custom Agents</a></li><li><a href="/guide/a2a-protocol.html">A2A Protocol</a></li></ul>',24)])])}const u=t(o,[["render",r]]);export{g as __pageData,u as default};
